    const prefix_L = new Array(n + 1).fill(0);
    const prefix_C = new Array(n + 1).fill(0);
    const prefix_T = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        prefix_L[i + 1] = prefix_L[i] + (s[i] === 'L' ? 1 : 0);
        prefix_C[i + 1] = prefix_C[i] + (s[i] === 'C' ? 1 : 0);
        prefix_T[i + 1] = prefix_T[i] + (s[i] === 'T' ? 1 : 0);
    }

    // Compute count_T_after
    const count_T_after = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        count_T_after[i] = count_T_after[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    // Compute sum_T_after_C
    const sum_T_after_C = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === 'C') {
            sum_T_after_C[i] = count_T_after[i + 1] + sum_T_after_C[i + 1];
        } else {
            sum_T_after_C[i] = sum_T_after_C[i + 1];
        }
    }

    // Calculate original count of "LCT" subsequences
    let original_count = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            original_count += prefix_L[i] * count_T_after[i + 1];
        }
    }

    // Calculate max insertions for L, C, T
    let max_insert_L = 0;
    for (let i = 0; i <= n; i++) {
        max_insert_L = Math.max(max_insert_L, sum_T_after_C[i]);
    }

    let max_insert_C = 0;
    for (let i = 0; i <= n; i++) {
        const current = prefix_L[i] * count_T_after[i + 1];
        max_insert_C = Math.max(max_insert_C, current);
    }

    let max_insert_T = 0;
    for (let i = 0; i <= n; i++) {
        const current = prefix_L[i] * prefix_C[i];
        max_insert_T = Math.max(max_insert_T, current);
